@startuml
skinparam classAttributeIconSize 0

interface HouseBuilder {
    void buildBasic();
    void buildBody();
    void buildRoof();
    House finish();
}

class CommonHouseBuilder {
    - house : House;

    +void buildBasic() 
    +void buildBody()  
    +void buildRoof()   
    +finish(): House

}


CommonHouseBuilder --|> HouseBuilder 

note "具体建造对象" as n1
n1 .. Decorate 


class LuxuryHouseBuilder{
- house : House ; 

+buildBasic()     
+buildBody()      
+buildRoof()       
+finish(): House  

 }



LuxuryHouseBuilder--|> HouseBuilder 



Decorator --> Client  


Decorate *--> HouseBuilder  




Client -> Decorator 




decorate o-> commonhousebuilder
commonhousebuilder*--> house
luxuryhousebuildero--> house

@enduml
